DROP TABLE IF EXISTS `broker`;
CREATE TABLE `broker` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `name` varchar(255) DEFAULT NULL COMMENT '名称',
  `com_rate` decimal(24,6) DEFAULT NULL COMMENT '佣金比例(commission_rate)',
  `five_free` tinyint(1) DEFAULT NULL COMMENT '是否免五',
  `adress` varchar(255) DEFAULT NULL COMMENT '开户地址',
  `telephone` varchar(20) DEFAULT NULL COMMENT '联系人电话',
  `sh_account` varchar(32) DEFAULT NULL COMMENT '沪A账号',
  `sz_account` varchar(32) DEFAULT NULL COMMENT '深A账号',
  `created_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

DROP TABLE IF EXISTS `day_memo`;
CREATE TABLE `day_memo` (
  `id` varchar(32) NOT NULL,
  `day` varchar(10) DEFAULT NULL COMMENT '日期',
  `title` varchar(255) DEFAULT NULL COMMENT '标题',
  `content` varchar(900) DEFAULT NULL COMMENT '内容',
  `user_id` varchar(32) DEFAULT NULL COMMENT '用户ID',
  `created_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8 COMMENT='每日备忘';

DROP TABLE IF EXISTS `stock_condition`;
CREATE TABLE `stock_condition` (
  `id` varchar(32) CHARACTER SET utf8 NOT NULL,
  `day` varchar(10) CHARACTER SET utf8 DEFAULT NULL,
  `high` decimal(24,4) DEFAULT NULL,
  `low` decimal(24,4) DEFAULT NULL,
  `open` decimal(24,4) DEFAULT NULL,
  `close` decimal(24,4) DEFAULT NULL,
  `code` varchar(10) CHARACTER SET utf8 DEFAULT NULL,
  `last_close` decimal(24,4) DEFAULT NULL COMMENT '前收盘',
  `offset_value` decimal(24,4) DEFAULT NULL COMMENT '涨跌额',
  `offset_rate` decimal(24,4) DEFAULT NULL COMMENT '涨跌幅',
  `turnover_rate` decimal(24,4) DEFAULT NULL COMMENT '换手率',
  `turnover` decimal(24,4) DEFAULT NULL COMMENT '成交量',
  `turnover_value` decimal(24,4) DEFAULT NULL COMMENT '成交金额',
  `created_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

DROP TABLE IF EXISTS `stock_history_position`;
CREATE TABLE `stock_history_position` (
  `id` varchar(32) NOT NULL,
  `user_id` varchar(32) DEFAULT NULL,
  `code` varchar(90) DEFAULT NULL COMMENT '代码',
  `profit` decimal(24,2) DEFAULT NULL COMMENT '当日收益',
  `term` varchar(32) DEFAULT NULL COMMENT '第几期持仓（以开仓日期为准）',
  `tenant_id` varchar(32) DEFAULT NULL COMMENT '租户号',
  `created_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_time` datetime DEFAULT NULL COMMENT '更新时间',
  `expend` decimal(24,2) DEFAULT NULL COMMENT '耗费资金',
  `income` decimal(24,2) DEFAULT NULL COMMENT '取回资金',
  `profit_rate` decimal(24,6) DEFAULT NULL COMMENT '盈利百分比',
  `hold_time` int(11) DEFAULT NULL COMMENT '持仓时长',
  `open_time` datetime DEFAULT NULL COMMENT '开仓时间',
  `close_time` datetime DEFAULT NULL COMMENT '清仓时间',
  `trade_count` int(11) DEFAULT NULL COMMENT '交易次数',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

DROP TABLE IF EXISTS `stock_info`;
CREATE TABLE `stock_info` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `code` varchar(10) NOT NULL COMMENT '代码',
  `name` varchar(32) DEFAULT NULL COMMENT '名称',
