  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=23547 DEFAULT CHARSET=utf8;

DROP TABLE IF EXISTS `stock_position`;
CREATE TABLE `stock_position` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `user_id` varchar(32) DEFAULT NULL COMMENT '用户',
  `code` varchar(90) DEFAULT NULL COMMENT '股票编码',
  `vol` int(11) DEFAULT NULL COMMENT '股票数量',
  `cost` decimal(24,6) DEFAULT NULL COMMENT '成本',
  `price` decimal(24,6) DEFAULT NULL COMMENT '当前价格',
  `created_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

DROP TABLE IF EXISTS `stock_position_day`;
CREATE TABLE `stock_position_day` (
  `id` varchar(32) CHARACTER SET utf8 NOT NULL DEFAULT '',
  `day` varchar(10) CHARACTER SET utf8 DEFAULT NULL,
  `code` varchar(90) CHARACTER SET utf8 DEFAULT 'utf8',
