  `total_profit` decimal(24,6) DEFAULT NULL,
  `day_profit` decimal(24,6) DEFAULT NULL,
  `term_trade_times` int(11) DEFAULT NULL,
  `term_open_time` datetime DEFAULT NULL,
  `term_expend` decimal(24,6) DEFAULT NULL,
  `term_income` decimal(24,6) DEFAULT NULL,
  `total_expend` decimal(24,6) DEFAULT NULL,
  `total_income` decimal(24,6) DEFAULT NULL,
  `month` varchar(10) DEFAULT NULL,
  `year` varchar(10) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=latin1;

DROP TABLE IF EXISTS `trade_detail`;
CREATE TABLE `trade_detail` (
  `id` varchar(32) NOT NULL COMMENT '主键',
  `user_id` varchar(32) DEFAULT NULL COMMENT '用户主键',
  `trade_time` datetime DEFAULT NULL COMMENT '交易时间',
  `opt` tinyint(1) DEFAULT NULL COMMENT '交易方向：1=buy;0:sell',
