  `code` varchar(10) DEFAULT NULL COMMENT '股票代码',
  `vol` int(11) DEFAULT NULL COMMENT '成交数量',
  `commission` decimal(24,2) DEFAULT NULL COMMENT '佣金',
  `tax` decimal(24,2) DEFAULT NULL COMMENT '税费',
  `day` varchar(12) DEFAULT NULL COMMENT '成交日',
