  `year` varchar(4) DEFAULT NULL COMMENT '成交年',
  `broker_id` varchar(32) DEFAULT NULL COMMENT '券商id',
  `created_time` datetime DEFAULT NULL COMMENT '创建时间',
  `updated_time` datetime DEFAULT NULL COMMENT '更新时间',
  `trans_fee` decimal(24,2) DEFAULT NULL COMMENT '过户费',
  `term` varchar(32) DEFAULT NULL COMMENT '第几期持仓',
  `row_key` varchar(64) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

